def gen(rng, size):
    n = max(1, size)
    nums = []
    for i in range(n):
        remaining = n - 1 - i
        if remaining == 0:
            nums.append(0)
        else:
            nums.append(rng.randrange(1, min(remaining, 50) + 1))
    return [nums]

