class Solution:
    def jump(self, nums):
        n = len(nums)
        INF = float('inf')
        dp = [0] + [INF] * (n - 1)
        for i in range(n):
            if dp[i] == INF:
                continue
            far = min(n - 1, i + nums[i])
            for j in range(i + 1, far + 1):
                if dp[i] + 1 < dp[j]:
                    dp[j] = dp[i] + 1
        return dp[n - 1]

